// TC:O(n log n) SC:O(n)
class Solution {
public:
    void merge(vector<pair<int, int>>& a, int low, int mid, int high,vector<int>& ans) {
        int left = low;
        int right = mid + 1;
        vector<pair<int, int>> temp;

        while (left <= mid && right <= high) {
            if (a[left].first > a[right].first) {
                ans[a[left].second] += (high - right + 1);
                temp.push_back(a[left++]);
            } else {
                temp.push_back(a[right++]);
            }
        }

        while (left <= mid)
            temp.push_back(a[left++]);
        while (right <= high)
            temp.push_back(a[right++]);

        for (int i = low; i <= high; i++)
            a[i] = temp[i - low];
    }

    void merge_sort(vector<pair<int, int>>& a, int low, int high,vector<int>& ans) {
        if (low >= high)
            return;
        int mid = (low + high) / 2;
        merge_sort(a, low, mid, ans);
        merge_sort(a, mid + 1, high, ans);
        merge(a, low, mid, high, ans);
    }

    vector<int> countSmaller(vector<int>& nums) {
        int n = nums.size();
        vector<int> ans(n, 0);
        vector<pair<int, int>> a;

        for (int i = 0; i < n; i++)
            a.push_back({nums[i], i});

        merge_sort(a, 0, n - 1, ans);
        return ans;
    }
};

Binary Search.Find Right Interval.cpp:
// Brute force TC:O(n² + n log n + n) SC:O(3n)
class Solution {
public:
    int linearSearch(vector<pair<int, int>>& arr, int num) {
        int ans = -1;
        for (int i = arr.size() - 1; i >= 0; i--)
            if (arr[i].first >= num)
                ans = arr[i].second;
        return ans;
    }
    vector<int> findRightInterval(vector<vector<int>>& intervals) {
        int n = intervals.size();
        vector<pair<int, int>> start, end;
        vector<int> ans(n, -1);
        for (int i = 0; i < n; i++)
            start.push_back({intervals[i][0], i});//O(n)
        for (int i = 0; i < n; i++)
            end.push_back({intervals[i][1], i}); // O(n)
        sort(start.begin(), start.end()); // O(n log n)
        sort(end.begin(), end.end());  // O(n log n)

        for (int i = 0; i < n; i++) { // overall O(n^2)
            ans[end[i].second] = linearSearch(start, end[i].first);
        }
        return ans;
    }
};
 // optmial TC:O(n log n) SC:O(3n)
class Solution {
public:
    int LowerB(vector<pair<int, int>>& arr, int num) {
        int ans = -1;
        int low = 0;
        int high = arr.size() - 1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (arr[mid].first >= num) {
                ans = arr[mid].second;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
    vector<int> findRightInterval(vector<vector<int>>& intervals) {
        int n = intervals.size();
        vector<pair<int, int>> start;
        vector<int> ans(n, -1);
        for (int i = 0; i < n; i++)
            start.push_back({intervals[i][0], i}); // O(n)

        sort(start.begin(), start.end()); // O(n log n)

        for (int i = 0; i < n; i++) { // overall O(log n)
            ans[i] = LowerB(start, intervals[i][1]);
        }
        return ans;
    }
};

Binary Search.Find Smallest Letter Greater Than Target:
// TC:O(log n) SC:O(1)
class Solution {
public:
    char nextGreatestLetter(vector<char>& letters, char target) {
        int n=letters.size();
        int low(0),high(n-1);
        while(low<=high){
            int mid(low+(high-low)/2);
            if(letters[mid]>target){
                high=mid-1;
            }else{
                low=mid+1;
            }
        }
        return (low<n)?letters[low]:letters[0];
    }
};

