// optimal  TC:O(log (min(a,b)) SC:O(1)
class Solution {
  public:
    int kthElement(vector<int> &a, vector<int> &b, int k) {
        int n1 = a.size(), n2 = b.size();
        if (n1 > n2) return kthElement(b, a, k); // ensure a is smaller

        int low = max(0, k - n2);
        int high = min(k, n1);

        while (low <= high) {
            int mid1 = low + (high - low) / 2;
            int mid2 = k - mid1; // how many from b

            int l1 = (mid1 > 0) ? a[mid1 - 1] : INT_MIN;
            int l2 = (mid2 > 0) ? b[mid2 - 1] : INT_MIN;
            int r1 = (mid1 < n1) ? a[mid1] : INT_MAX;
            int r2 = (mid2 < n2) ? b[mid2] : INT_MAX;

            if (l1 <= r2 && l2 <= r1) {
                return max(l1, l2);
            } else if (l1 > r2) {
                high = mid1 - 1;
            } else {
                low = mid1 + 1;
            }
        }
        return -1; // shouldn't reach here
    }
};

// TC:O(n · log(maxValue)) SC:O(1)
class Solution {
public:
    int countSmallerNumbers(vector<vector<int>>& matrix, int mid) {
        int n = matrix.size();
        int row = 0;
        int col = n - 1;
        int cnt = 0;
        while (row < n && col >= 0) {
            if (matrix[row][col] <= mid) {
                cnt += (col + 1);
                row++; // go down
            } else
                col--;
        }
        return cnt;
    }
    int kthSmallest(vector<vector<int>>& matrix, int k) {
        int rows = matrix.size();
        int cols = matrix[0].size();
        if (rows * cols < 2)
            return matrix[rows - 1][cols - 1];
        int low = matrix[0][0];
        int high = matrix[rows - 1][cols - 1];
        while (low < high) {
            int mid = low + (high - low) / 2;

            if (countSmallerNumbers(matrix, mid) < k)
                low = mid + 1; // go left and find greater no
            else {
                high = mid; // go right and find smaller no
            }
        }
        return low;
    }
};

Binary Search.Kth Smallest Product of Two Sorted Array:
 // brute force approach TC:O(n1 × n2 log(n1 × n2)) SC:O(nums1 * nums2)
class Solution {
public:
    long long kthSmallestProduct(vector<int>& nums1, vector<int>& nums2, long long k) {
        vector<long long> products;
        for(int a:nums1){
            for(int b:nums2){
                products.emplace_back(1ll * a * b);
            }
        }
        sort(products.begin(),products.end());
        return products[k-1];
    }
};
// optimalTC:O(n1⋅logn2⋅log(max_product - min_product))  SC:O(1)
class Solution {
public:
    long long checkLess(const vector<int>& a, const vector<int>& b,long long mid) {
        long long cnt = 0;
        int n = b.size();
        for (int x : a) {
            if (x > 0) {
                long long target = (long long)floor((double)mid / x);

                cnt += upper_bound(b.begin(), b.end(), target) - b.begin();

            } else if (x < 0) {
                cnt += b.end() - lower_bound(b.begin(), b.end(),
                                             (long long)ceil((double)mid / x));
            } else {
                if (mid >= 0)
                    cnt += n;
            }
        }
        return cnt;
    }
    long long kthSmallestProduct(vector<int>& a, vector<int>& b, long long k) {
        long long low = min({1LL * a[0] * b[0], 1LL * a[0] * b.back(),
                             1LL * a.back() * b[0], 1LL * a.back() * b.back()});
        long long high =
            max({1LL * a[0] * b[0], 1LL * a[0] * b.back(),
                 1LL * a.back() * b[0], 1LL * a.back() * b.back()});

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (checkLess(a, b, mid) >= k)
                high = mid - 1;
            else
                low = mid + 1;
        }
        return low;
    }
};

