class Solution {
public:
    bool check(vector<int>& a, int val, int k) {
        int cnt = 1;
        int allocated = 0;
        for (int n : a) {
            if (allocated + n > val) {
                allocated = n;
                cnt++;
            } else
                allocated += n;
        }
        return (cnt <= k);
    }
    int splitArray(vector<int>& a, int k) {
        if (k > a.size())
            return -1;
        int midLim = *max_element(a.begin(), a.end());
        int maxlim = accumulate(a.begin(), a.end(), 0);
        for (int i = midLim; i <= maxlim; i++) {
            if (check(a, i, k))
                return i;
        }
        return -1;
    }
};

