// brute TC:O(n) SC:O(n)
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* doubleIt(ListNode* head) {
        if (!head)
            return nullptr;
        ListNode* temp = head;
        stack<int> stk;
        while (temp) {
            stk.push(temp->val);
            temp = temp->next;
        }
        ListNode* newHead=nullptr;
        int carry = 0;
        while (!stk.empty()) {
            long long mul = stk.top() * 2 + carry;
            stk.pop();
            ListNode* nn = new ListNode(mul % 10);
            carry = mul / 10;
            nn->next = newHead;
            newHead = nn;
        }
        if (carry) {
            ListNode* nn = new ListNode(carry);
            nn->next = newHead;
            newHead = nn;
        }
        return newHead;
    }
};
