 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* reverseBetween(ListNode* head, int left, int right) {
        if (!head)
            return nullptr;
        if (!head->next)
            return head;

        ListNode* dummy = new ListNode(-1);
        dummy->next = head;
        ListNode* beforeRev = dummy;
        for (int i = 0; i < left-1; i++) 
            beforeRev = beforeRev->next;

        ListNode* revHead = beforeRev->next;
        ListNode* curr=revHead;
        ListNode* prev=beforeRev;
        for(int i=0;i<right-left+1;i++){
            ListNode* next=curr->next;
            curr->next=prev;
            prev=curr;
            curr=next;
        }
        revHead->next=curr;
        beforeRev->next=prev;
        return dummy->next;

    }
};

Linked List.Reverse Nodes in k-Group.cpp:
// TC:O(2n) SC:O(1)
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* getKthNode(ListNode* head, int k) {
        ListNode* temp = head;
        while (temp && k > 1) {
            temp = temp->next;
            k--;
        }
        return temp;
    }
    ListNode* reverseList(ListNode* head) {
        ListNode* prev = nullptr;
        ListNode* curr = head;
        while (curr) {
            ListNode* next = curr->next;
            curr->next = prev;
            prev = curr;
            curr = next;
        }
        return prev;
    }
    ListNode* reverseKGroup(ListNode* head, int k) {
        ListNode* temp = head;
        ListNode* prevNode = nullptr;
        while (temp) {

            ListNode* kthNode = getKthNode(temp, k);
            if (!kthNode) {
                if (prevNode)
                    prevNode->next = temp;
                break;
            }

            ListNode* nextNode = kthNode->next;
            kthNode->next = nullptr;

            reverseList(temp);
            if (temp == head)
                head = kthNode;
            else
                prevNode->next = kthNode;
            prevNode = temp;
            temp = nextNode;
        }
        return head;
    }
};

Linked List.Reverse alternate nodes in Link List.cpp:
// TC:O(n) SC:O(1)
/*
  reverse alternate nodes and append at the end
  The input list will have at least one element
  Node is defined as
  struct Node
  {
      int data;
      struct Node *next;

      Node(int x){
        data = x;
        next = NULL;
      }

   };

*/
class Solution {
  public:
   Node* reverseList(Node* &head){
      Node* curr=head;
      Node* prev=nullptr;
      while(curr){
          Node* next=curr->next;
          curr->next=prev;
          prev=curr;
          curr=next;
      }
      return prev;
   }
    void rearrange(Node* head) {
        if(!head)return;
        Node* org=head;
        Node* arr=head->next;
        Node* arrHead=head->next;
        while(arr && arr->next){
            org->next=arr->next;
            org=org->next;
            arr->next=org->next;
            arr=arr->next;
        }
        arrHead=reverseList(arrHead);
        org->next=arrHead;
    }
};

Linked List.Rotate List.cpp:
// TC:O(n) SC:O(1)
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* rotateRight(ListNode* head, int k) {
        if (k == 0 || head == nullptr)
            return head;
        int len = 1;
        ListNode* curr = head;
        while (curr->next != nullptr) {
            curr = curr->next;
            len++;
        }
        k %= len;
        if (k == 0)
            return head;
        curr->next = head;
        curr = head;
        for (int i = 0; i < len-k-1; i++)
            curr = curr->next;

        head = curr->next;
        curr->next=nullptr;
        return head;
    }
};

