    void findAllPermute(int ind,vector<int> &nums,vector<vector<int>> &ans){
        if(ind == nums.size()){
            ans.emplace_back(nums);
            return;

        }
        for(int i=ind;i<nums.size();i++){
            swap(nums[ind],nums[i]);
            findAllPermute(ind+1,nums,ans);
            swap(nums[ind],nums[i]);
        }
    }
