class Solution {
public:
    int numSubarraysWithSum(vector<int>& nums, int goal) {
        int n = nums.size();
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            int currSum = 0;
            for (int j = i; j < n; j++) {
                currSum += nums[j];
                if (currSum == goal)
                    cnt++;
            }
        }
        return cnt;
    }
};
// optimal TC:O(n) SC:O(1)
class Solution {
public:
    int slidingWindow(vector<int>& nums, int goal,int &n) {
        if (goal < 0)
            return 0;

        int cnt = 0;
        int l = 0, r = 0;
        int sum = 0;
        while (r < n) {
            sum += nums[r];
            while (sum > goal)
                sum -= nums[l++];
            if (sum <= goal)
                cnt += (r - l) + 1;
            r++;
        }
        return cnt;
    }
    int numSubarraysWithSum(vector<int>& nums, int goal) {
         int n = nums.size();
        return slidingWindow(nums, goal,n) - slidingWindow(nums, goal - 1,n);
    }
};

