class Solution {
public:
    int totalFruit(vector<int>& nums) {
        int n = nums.size();
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            int basket1 = -1, basket2 = -1;
            for (int j = i; j < n; j++) {
                if (basket1 == -1)
                    basket1 = nums[j];
                if (basket2 == -1 && nums[j] != basket1)
                    basket2 = nums[j];
                if (nums[j] == basket1 || nums[j] == basket2)
                    maxLen = max(maxLen, j - i + 1);
                else
                    break;
            }
        }
        return maxLen;
    }
};
