class Solution {
public:
    int characterReplacement(string s, int k) {
        int n = s.length();
        int maxSub = 0;
        for (int i = 0; i < n; i++) {
            unordered_map<char, int> mpp;
            int maxfreq = 0;
            for (int j = i; j < n; j++) {
                mpp[s[j]]++;
                maxfreq = max(maxfreq, mpp[s[j]]);
                int charReplaced = (j - i + 1) - maxfreq;
                if (charReplaced <= k)
                    maxSub = max(maxSub, j - i + 1);
                else
                    break;
            }
        }
        return maxSub;
    }
};
