class MyQueue {
    stack<int> stk;

public:
    MyQueue() {}

    void push(int x) { stk.push(x); }

    int pop() {
        if (stk.size() == 1) {
            int x = stk.top();
            stk.pop();
            return x;
        }
        int top = stk.top();
        stk.pop();
        int res = pop();
        stk.push(top);
        return res;
    }

    int peek() {
        if (stk.size() == 1) {
            return stk.top(); // don't pop
        }

        int top = stk.top();
        stk.pop();

        int res = peek();

        stk.push(top);

        return res;
    }

    bool empty() { return stk.empty(); }
};

