        stack<int> stk;
        int maxArea = 0;
        for (int i = 0; i < n; i++) {
            while (!stk.empty() && arr[stk.top()] > arr[i]) {
                int nse = i;
                int element = arr[stk.top()];stk.pop();
                int pse = stk.empty() ? -1 : stk.top();
                maxArea = max(maxArea, element * (nse - pse - 1));
            }
