        for (int n : arr)
            maxNum = max(maxNum, n);
        return maxNum;
    }
    vector<int> maxSlidingWindow(vector<int>& nums, int k) {
        int n = nums.size();
        vector<vector<int>> karr; 
        vector<int> ans;
        for (int i = 0; i < n-k+1; i++) {
            vector<int> temp;
            for (int j = 0; j < k; j++) {
                temp.emplace_back(nums[i+j]);
            }
            karr.emplace_back(temp);
        }
        for (int i = 0; i < karr.size(); i++) {
            ans.emplace_back(maxEle(karr[i]));
        }
        return ans;
    }
};
