            for(int j=0;j<row;j++){
                if(i == j)continue;
                if(mat[i][j] == 1){
                    bool celebrity  = true;
                    for(int k=0;k<col;k++){
                        if(k == j)
                            continue;
                        if(mat[k][j]!=1 || mat[j][k]!=0){
                            celebrity = false;
                            break;
                        }
                    }
                    if(celebrity)
                        return j;
                }
            }
        }
        return -1;
    }
};
