class Solution {
public:
    string addBinary(string a, string b) {
        string res="";
        int i=a.length()-1;
        int j=b.length()-1;
        int carry=0;
        while(i>=0 || j>=0 || carry){
            int sum=carry;
            if(i>=0) sum+=a[i--]-'0';
            if(j>=0) sum+=b[j--]-'0';
            carry=sum/2;
            res+=(sum%2)+'0';
        }
        reverse(res.begin(),res.end());
        return res;
    }
};

