Tree.AVL Tree Insertion.cpp:
// TC: O(log N) SC: O(log N)
class Solution {
public:
    int height(Node* node) {
        return node ? node->height : 0;
    }

    int getBalance(Node* node) {
        return node ? height(node->left) - height(node->right) : 0;
    }

    int max(int a, int b) {
        return (a > b) ? a : b;
    }

    // Right Rotation (LL)
    Node* rightRotate(Node* y) {
        Node* x = y->left;
        Node* T2 = x->right;

        x->right = y;
        y->left = T2;

        // update heights (BOTTOM UP)
        y->height = 1 + max(height(y->left), height(y->right));
        x->height = 1 + max(height(x->left), height(x->right));

        return x;
    }

    // Left Rotation (RR)
    Node* leftRotate(Node* x) {
        Node* y = x->right;
        Node* T2 = y->left;

        y->left = x;
        x->right = T2;

        // update heights (BOTTOM UP)
        x->height = 1 + max(height(x->left), height(x->right));
        y->height = 1 + max(height(y->left), height(y->right));

        return y;
    }

    Node* insertToAVL(Node* node, int data) {
        // Normal BST insert
        if (!node)
            return new Node(data);

        if (data < node->data)
            node->left = insertToAVL(node->left, data);
        else if (data > node->data)
            node->right = insertToAVL(node->right, data);
        else
            return node; // duplicates not allowed

        // Update height
        node->height = 1 + max(height(node->left), height(node->right));

        int balance = getBalance(node);

        // LL
        if (balance > 1 && data < node->left->data)
            return rightRotate(node);

        // RR
        if (balance < -1 && data > node->right->data)
            return leftRotate(node);

        // LR
        if (balance > 1 && data > node->left->data) {
            node->left = leftRotate(node->left);
            return rightRotate(node);
        }

        // RL
        if (balance < -1 && data < node->right->data) {
            node->right = rightRotate(node->right);
            return leftRotate(node);
        }

        return node;
    }
};

Tree.All Nodes Distance K in Binary Tree.cpp:
// TC:O(n) SC:O(n) 
class Solution {
public:
   void markParent(TreeNode* root, unordered_map<TreeNode* ,TreeNode*> &parent){
    if(root==nullptr)return;
     queue<TreeNode*> q;
     q.push(root);
     while(!q.empty()){
        TreeNode* node = q.front();
        q.pop();
        if(node->left){
            parent[node->left] = node;
            q.push(node->left);
        }
        if(node->right){
            parent[node->right]  =  node;
            q.push(node->right);
        }
     }
   } 
    queue<TreeNode*> findNodesAtDistance(TreeNode* target,unordered_map<TreeNode* ,TreeNode*> &parent,int k){
        queue<TreeNode*> q;
        unordered_map<TreeNode* ,bool> visited;

        q.push(target);
        visited[target] = true;
        int distance = 0;
        while(!q.empty()){
            int size = q.size();
            int flag = false;
            if(distance == k)break;
            for(int i=0;i<size;i++){
                TreeNode* node = q.front();
                q.pop();
                if(node->left && !visited[node->left]){
                    visited[node->left] = true;
                    q.push(node->left);
                    flag = true;
                }
                if(node->right && !visited[node->right]){
                    visited[node->right] = true;
                    q.push(node->right);
                    flag = true;
                }
                if(parent[node] && !visited[parent[node]]){
                    visited[parent[node]] = true;
                    q.push(parent[node]);
                    flag = true;
                }

            }
             distance++;
        }
        return q;

    }
    vector<int> distanceK(TreeNode* root, TreeNode* target, int k) {
        unordered_map<TreeNode* ,TreeNode*> parent;
        markParent(root,parent);
        queue<TreeNode*> q = findNodesAtDistance(target,parent,k);
        vector<int> answers;
        while(!q.empty()){
            answers.emplace_back(q.front()->val);
            q.pop();
        }
        return answers;
    }
};

Tree.Amount of Time for Binary Tree to Be Inf:
// TC:O(n) SC:O(n) 
class Solution {
public:
    TreeNode* bfsToParent(TreeNode* root,
                          unordered_map<TreeNode*, TreeNode*>& parent,
                          int start) {

        queue<TreeNode*> q;
        q.push(root);
        TreeNode* target = nullptr;
        while (!q.empty()) {
            TreeNode* node = q.front();
            q.pop();

            if (node->val == start)
                target = node;

            if (node->left) {
                parent[node->left] = node;
                q.push(node->left);
            }

            if (node->right) {
                parent[node->right] = node;
                q.push(node->right);
            }
        }

        return target;
    }

    int infect(TreeNode* start, unordered_map<TreeNode*, TreeNode*>& parent) {

        queue<TreeNode*> q;
        unordered_map<TreeNode*, bool> visited;

        q.push(start);
        visited[start] = true;

        int time_taken = 0;

        while (!q.empty()) {
            int size = q.size();
            bool flag = false;

            for (int i = 0; i < size; i++) {
                TreeNode* node = q.front();
                q.pop();

                if (node->left && !visited[node->left]) {
                    q.push(node->left);
                    visited[node->left] = true;
                    flag = true;
                }

                if (node->right && !visited[node->right]) {
                    q.push(node->right);
                    visited[node->right] = true;
                    flag = true;
                }

                if (parent[node] && !visited[parent[node]]) {
                    q.push(parent[node]);
                    visited[parent[node]] = true;
                    flag = true;
                }
            }

            if (flag)
                time_taken++;
        }

        return time_taken;
    }

    int amountOfTime(TreeNode* root, int start) {

        unordered_map<TreeNode*, TreeNode*> parent;

        TreeNode* startNode = bfsToParent(root, parent, start);

        return infect(startNode, parent);
    }
};

