class Solution {
public:
    int countKDifference(vector<int>& nums, int k) {
        unordered_map<int,int> mpp;
        int cnt = 0;
        for (int n : nums) {
           cnt+=mpp[n-k];
           cnt+=mpp[n+k];
           mpp[n]++;
        }
        return cnt;
    }
};

